-- ===================================
-- Copy All 184 Hardcoded Students to Supabase
-- Generated automatically from app.js
-- ===================================

-- Insert all students from hardcoded data
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    email = EXCLUDED.email,
    cohort = EXCLUDED.cohort,
    gpa = EXCLUDED.gpa,
    risk = EXCLUDED.risk,
    attendance = EXCLUDED.attendance,
    account_status = EXCLUDED.account_status,
    updated_at = NOW();

SELECT '✅ 184 students copied to Supabase!' AS status;

-- Verify the data
SELECT cohort, COUNT(*) as count FROM students GROUP BY cohort ORDER BY cohort;
